// Standard third-person camera setup
AMyCharacter::AMyCharacter() {
    // Spring Arm
    SpringArm = CreateDefaultSubobject<USpringArmComponent>(TEXT("SpringArm"));
    SpringArm->SetupAttachment(RootComponent);
    SpringArm->TargetArmLength = 300.f;
    SpringArm->bUsePawnControlRotation = true; // Follow mouse
    SpringArm->bDoCollisionTest = true;         // Avoid walls
    SpringArm->bEnableCameraLag = true;
    SpringArm->CameraLagSpeed = 10.f;

    // Camera
    Camera = CreateDefaultSubobject<UCameraComponent>(TEXT("Camera"));
    Camera->SetupAttachment(SpringArm);
    Camera->FieldOfView = 90.f;
}

// Camera shake on hit
void AMyCharacter::OnDamageTaken() {
    APlayerController* PC = Cast<APlayerController>(GetController());
    if (PC && PC->PlayerCameraManager) {
        PC->PlayerCameraManager->StartCameraShake(HitCameraShake, 1.0f);
    }
}

// Blend to a cinematic camera
void AMyTrigger::SwitchToCamera(ACameraActor* NewCamera) {
    APlayerController* PC = GetWorld()->GetFirstPlayerController();
    PC->SetViewTargetWithBlend(NewCamera, 1.5f, EViewTargetBlendFunction::VTBlend_EaseInOut);
}
